# Approach 1 — Pythonic one-liner (preferred in interviews)
def getConcatenation(nums: list[int]) -> list[int]:
    return nums + nums  # Python copies both lists into a new list of size 2n

# Approach 2 — Explicit modulo (shows understanding of the index relationship)
def getConcatenation(nums: list[int]) -> list[int]:
    n = len(nums)
    result = [0] * (2 * n)       # allocate exact output size upfront
    for i in range(2 * n):
        result[i] = nums[i % n]  # modulo maps second half back to first half
    return result

# Approach 3 — In-place append (O(1) extra space, but mutates input)
def getConcatenation(nums: list[int]) -> list[int]:
    n = len(nums)                # MUST capture before loop — list grows during iteration
    for i in range(n):
        nums.append(nums[i])     # safe: reading from already-frozen first half
    return nums
